import type { ComponentProps } from 'react';
import { Select as SelectPrimitive } from '@base-ui/react/select';
import { clsx } from 'clsx';
import {
  CheckIcon,
  ChevronDownIcon,
  ChevronUpDownIcon,
  ChevronUpIcon,
  PopupArrowIcon,
} from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Select.module.css';

type IndicatorPosition = 'start' | 'end' | 'none';

type SelectContentProps = SelectPrimitive.Popup.Props & {
  align?: SelectPrimitive.Positioner.Props['align'];
  alignItemWithTrigger?: SelectPrimitive.Positioner.Props['alignItemWithTrigger'];
  alignOffset?: SelectPrimitive.Positioner.Props['alignOffset'];
  arrowPadding?: SelectPrimitive.Positioner.Props['arrowPadding'];
  collisionAvoidance?: SelectPrimitive.Positioner.Props['collisionAvoidance'];
  collisionBoundary?: SelectPrimitive.Positioner.Props['collisionBoundary'];
  collisionPadding?: SelectPrimitive.Positioner.Props['collisionPadding'];
  side?: SelectPrimitive.Positioner.Props['side'];
  sideOffset?: SelectPrimitive.Positioner.Props['sideOffset'];
  showArrow?: boolean;
};

const SELECT_CONTENT_SIDE_OFFSET = 8;
const Select = SelectPrimitive.Root;

function SelectField({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="select-field" className={clsx(styles.field, className)} {...props} />;
}

function SelectLabel({ className, ...props }: SelectPrimitive.Label.Props) {
  return (
    <SelectPrimitive.Label
      data-slot="select-label"
      className={mergeClassName(className, styles.label)}
      {...props}
    />
  );
}

function SelectTrigger({ className, ...props }: SelectPrimitive.Trigger.Props) {
  return (
    <SelectPrimitive.Trigger
      data-slot="select-trigger"
      className={mergeClassName(className, styles.trigger)}
      {...props}
    />
  );
}

function SelectValue({ className, ...props }: SelectPrimitive.Value.Props) {
  return (
    <SelectPrimitive.Value
      data-slot="select-value"
      className={mergeClassName(className, styles.value)}
      {...props}
    />
  );
}

function SelectIcon({ className, children, ...props }: SelectPrimitive.Icon.Props) {
  return (
    <SelectPrimitive.Icon
      data-slot="select-icon"
      className={mergeClassName(className, styles.icon)}
      {...props}
    >
      {children ?? <ChevronUpDownIcon className={styles.iconSvg} />}
    </SelectPrimitive.Icon>
  );
}

function SelectPortal(props: SelectPrimitive.Portal.Props) {
  return <SelectPrimitive.Portal data-slot="select-portal" {...props} />;
}

function SelectBackdrop({ className, ...props }: SelectPrimitive.Backdrop.Props) {
  return (
    <SelectPrimitive.Backdrop
      data-slot="select-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function SelectPositioner({ className, ...props }: SelectPrimitive.Positioner.Props) {
  return (
    <SelectPrimitive.Positioner
      data-slot="select-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function SelectPopup({ className, ...props }: SelectPrimitive.Popup.Props) {
  return (
    <SelectPrimitive.Popup
      data-slot="select-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function SelectArrow({ className, children, ...props }: SelectPrimitive.Arrow.Props) {
  return (
    <SelectPrimitive.Arrow
      data-slot="select-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? <ArrowSvg className={styles.arrowSvg} />}
    </SelectPrimitive.Arrow>
  );
}

function SelectContent({
  className,
  children,
  showArrow = false,
  alignItemWithTrigger,
  side,
  sideOffset = SELECT_CONTENT_SIDE_OFFSET,
  align,
  alignOffset,
  arrowPadding,
  collisionAvoidance,
  collisionBoundary,
  collisionPadding,
  ...popupProps
}: SelectContentProps) {
  return (
    <SelectPortal>
      <SelectPositioner
        alignItemWithTrigger={alignItemWithTrigger}
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        arrowPadding={arrowPadding}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <SelectPopup className={className} {...popupProps}>
          {showArrow ? <SelectArrow /> : null}
          {children}
        </SelectPopup>
      </SelectPositioner>
    </SelectPortal>
  );
}

function SelectScrollUpArrow({
  className,
  children,
  ...props
}: SelectPrimitive.ScrollUpArrow.Props) {
  return (
    <SelectPrimitive.ScrollUpArrow
      data-slot="select-scroll-up-arrow"
      className={mergeClassName(className, styles.scrollArrow)}
      {...props}
    >
      {children ?? <ChevronUpIcon className={styles.scrollArrowIcon} />}
    </SelectPrimitive.ScrollUpArrow>
  );
}

function SelectScrollDownArrow({
  className,
  children,
  ...props
}: SelectPrimitive.ScrollDownArrow.Props) {
  return (
    <SelectPrimitive.ScrollDownArrow
      data-slot="select-scroll-down-arrow"
      className={mergeClassName(className, styles.scrollArrow)}
      {...props}
    >
      {children ?? <ChevronDownIcon className={styles.scrollArrowIcon} />}
    </SelectPrimitive.ScrollDownArrow>
  );
}

function SelectList({ className, ...props }: SelectPrimitive.List.Props) {
  return (
    <SelectPrimitive.List
      data-slot="select-list"
      className={mergeClassName(className, styles.list)}
      {...props}
    />
  );
}

function SelectItem({
  className,
  indicator,
  ...props
}: SelectPrimitive.Item.Props & { indicator?: IndicatorPosition }) {
  return (
    <SelectPrimitive.Item
      data-slot="select-item"
      data-indicator-position={indicator}
      className={mergeClassName(className, styles.item)}
      {...props}
    />
  );
}

function SelectItemIndicator({
  className,
  children,
  ...props
}: SelectPrimitive.ItemIndicator.Props) {
  return (
    <SelectPrimitive.ItemIndicator
      data-slot="select-item-indicator"
      className={mergeClassName(className, styles.itemIndicator)}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </SelectPrimitive.ItemIndicator>
  );
}

function SelectItemText({ className, ...props }: SelectPrimitive.ItemText.Props) {
  return (
    <SelectPrimitive.ItemText
      data-slot="select-item-text"
      className={mergeClassName(className, styles.itemText)}
      {...props}
    />
  );
}

function SelectItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-content"
      className={clsx(styles.itemTextContent, className)}
      {...props}
    />
  );
}

function SelectItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-icon"
      className={clsx(styles.itemTextIcon, className)}
      {...props}
    />
  );
}

function SelectItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-label"
      className={clsx(styles.itemTextLabel, className)}
      {...props}
    />
  );
}

function SelectSeparator({ className, ...props }: SelectPrimitive.Separator.Props) {
  return (
    <SelectPrimitive.Separator
      data-slot="select-separator"
      className={mergeClassName(className, styles.separator)}
      {...props}
    />
  );
}

function SelectGroup({ className, ...props }: SelectPrimitive.Group.Props) {
  return (
    <SelectPrimitive.Group
      data-slot="select-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
}

function SelectGroupLabel({ className, ...props }: SelectPrimitive.GroupLabel.Props) {
  return (
    <SelectPrimitive.GroupLabel
      data-slot="select-group-label"
      className={mergeClassName(className, styles.groupLabel)}
      {...props}
    />
  );
}

function ArrowSvg(props: ComponentProps<'svg'>) {
  return (
    <PopupArrowIcon
      fillClassName={styles.arrowFill}
      outerStrokeClassName={styles.arrowOuterStroke}
      innerStrokeClassName={styles.arrowInnerStroke}
      {...props}
    />
  );
}

export {
  Select,
  SelectField,
  SelectLabel,
  SelectTrigger,
  SelectValue,
  SelectIcon,
  SelectPortal,
  SelectBackdrop,
  SelectPositioner,
  SelectPopup,
  SelectArrow,
  SelectContent,
  SelectScrollUpArrow,
  SelectScrollDownArrow,
  SelectList,
  SelectItem,
  SelectItemIndicator,
  SelectItemText,
  SelectItemTextContent,
  SelectItemTextIcon,
  SelectItemTextLabel,
  SelectSeparator,
  SelectGroup,
  SelectGroupLabel,
};

@layer ui.components {
  .field {
    display: inline-flex;
    flex-direction: column;
    gap: var(--select-field-gap, 0.375rem);
  }

  .label {
    display: inline-flex;
    align-items: center;
    font-size: var(--select-label-font-size, var(--text-sm));
    line-height: var(--select-label-line-height, var(--line-height-text-sm));
    font-weight: var(--select-label-font-weight, var(--weight-medium));
    color: var(--select-color, var(--color-foreground));
    cursor: default;
  }

  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--select-width, 14rem);
    min-height: var(--select-control-height, var(--size-lg));
    align-items: center;
    justify-content: flex-start;
    gap: var(--select-trigger-gap, 0.75rem);
    margin: 0;
    padding: 0 var(--select-trigger-padding-x, 0.875rem);
    border: var(--select-border-width, var(--border-width-sm)) solid
      var(--select-border-color, var(--color-border));
    border-radius: var(--select-radius, var(--radius-md));
    background-color: var(--select-bg, var(--color-background));
    color: var(--select-color, var(--color-foreground));
    font: inherit;
    text-align: start;
    outline: 0;
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default),
      outline-color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--select-bg-hover, var(--color-accent));
      }
    }

    &[data-popup-open] {
      background-color: var(--select-bg-active, var(--color-muted));
    }

    &:focus-visible {
      border-color: var(--select-focus-ring-color, var(--color-ring));
      outline: var(--select-focus-ring-width, var(--select-border-width, var(--border-width-sm)))
        solid var(--select-focus-ring-color, var(--color-ring));
      outline-offset: var(--select-focus-ring-offset, -1px);
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--select-disabled-opacity, var(--opacity-disabled));
    }
  }

  .value {
    min-width: 0;
    flex: 1;
    text-align: start;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;

    &[data-placeholder] {
      color: var(--select-placeholder-color, var(--color-muted-foreground));
    }
  }

  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-left: auto;
    width: var(--select-icon-size, 0.875rem);
    height: var(--select-icon-size, 0.875rem);
    flex-shrink: 0;
    color: var(--select-icon-color, var(--color-muted-foreground));
  }

  .iconSvg {
    width: var(--select-icon-svg-size, 1rem);
    height: var(--select-icon-svg-size, 1rem);
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--select-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--select-backdrop-blur, 4px)));
    transition:
      opacity var(--select-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--select-backdrop-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--select-backdrop-starting-opacity, 0);
      backdrop-filter: var(--select-backdrop-starting-blur, none);
    }

    &[data-ending-style] {
      opacity: var(--select-backdrop-ending-opacity, 0);
      backdrop-filter: var(--select-backdrop-ending-blur, none);
    }
  }

  .positioner {
    z-index: var(--z-popup);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    position: relative;
    width: var(--anchor-width);
    min-width: min(var(--anchor-width), var(--available-width));
    max-width: var(--available-width);
    max-height: min(var(--select-popup-max-height, 24rem), var(--available-height));
    overflow: visible;
    border: 0;
    border-radius: var(--select-radius, var(--radius-md));
    background-color: var(--select-popup-bg, var(--color-popover));
    color: var(--select-color, var(--color-popover-foreground));
    outline: var(--select-popup-border-width, var(--border-width-sm)) solid
      var(--select-popup-border-color, var(--color-border));
    box-shadow: var(--select-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      opacity var(--select-popup-transition, var(--transition-default)),
      transform var(--select-popup-transition, var(--transition-default)),
      translate var(--select-popup-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--select-popup-starting-opacity, 0);
      translate: var(--select-popup-starting-translate-x, 0)
        var(--select-popup-starting-translate-y, 0);
      transform: scale(var(--select-popup-starting-scale, var(--scale-popup)));
    }

    &[data-ending-style] {
      opacity: var(--select-popup-ending-opacity, 0);
      translate: var(--select-popup-ending-translate-x, 0) var(--select-popup-ending-translate-y, 0);
      transform: scale(var(--select-popup-ending-scale, var(--scale-popup)));
    }

    &[data-side='none'] {
      min-width: calc(var(--anchor-width) + var(--select-overlap-offset, 1rem));
      transition: none;
      transform: none;
      opacity: 1;
    }
  }

  .arrow {
    display: flex;
    color: var(--select-popup-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--select-arrow-size, 0.5rem) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--select-arrow-size, 0.5rem) * -1);
      rotate: 0deg;
    }

    &[data-side='left'] {
      right: calc(var(--select-arrow-inline-offset, 0.8125rem) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--select-arrow-inline-offset, 0.8125rem) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--select-arrow-width, 1.25rem);
    height: var(--select-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(--select-arrow-stroke-color, var(--select-popup-border-color, var(--color-border)));
  }

  .arrowInnerStroke {
    fill: var(--select-popup-bg, var(--color-popover));
  }

  .scrollArrow {
    display: inline-flex;
    inset-inline: 0;
    width: auto;
    height: var(--select-scroll-arrow-height, 1rem);
    align-items: center;
    justify-content: center;
    background-color: var(--select-popup-bg, var(--color-popover));
    color: var(--select-scroll-arrow-color, var(--select-color, var(--color-foreground)));
    cursor: default;
    z-index: var(--select-scroll-arrow-z-index, 1);

    &[data-direction='up'] {
      top: 0;
    }

    &[data-direction='down'] {
      bottom: 0;
    }
  }

  .scrollArrowIcon {
    width: var(--select-scroll-arrow-icon-size, 0.875rem);
    height: var(--select-scroll-arrow-icon-size, 0.875rem);
  }

  .list {
    box-sizing: border-box;
    max-height: min(
      var(--select-list-max-height, var(--select-popup-max-height, 24rem)),
      var(--available-height)
    );
    overflow-y: auto;
    overscroll-behavior: contain;
    padding-block: var(--select-list-padding-y, var(--popup-list-padding-y, 0.25rem));
    scroll-padding-block: var(--select-list-scroll-padding-y, var(--popup-list-padding-y, 0.25rem));
    outline: 0;
  }

  .item {
    box-sizing: border-box;
    position: relative;
    display: grid;
    grid-template-columns:
      var(--select-item-indicator-size, var(--popup-check-indicator-size, 0.75rem))
      minmax(0, 1fr);
    align-items: center;
    gap: var(--select-item-gap, var(--popup-check-gap, 0.5rem));
    width: 100%;
    min-height: var(--select-item-min-height, var(--popup-item-min-height, 2rem));
    padding-block: var(--select-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(
        --select-check-padding-x-start,
        var(--popup-check-padding-x-start, 0.625rem)
      )
      var(--select-item-padding-x-end, var(--popup-item-padding-x-end, 1rem));
    border-radius: var(--select-item-radius, 0);
    outline: 0;
    cursor: default;
    user-select: none;
    font: inherit;
    font-size: var(--select-item-font-size, var(--popup-item-font-size, var(--text-sm)));
    line-height: var(
      --select-item-line-height,
      var(--popup-item-line-height, var(--line-height-text-sm))
    );
    color: var(--select-item-color, var(--select-color, var(--color-foreground)));

    & > .itemIndicator {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: var(--select-item-indicator-size, var(--popup-check-indicator-size, 0.75rem));
      height: var(--select-item-indicator-size, var(--popup-check-indicator-size, 0.75rem));
    }

    & > .itemText {
      grid-column-start: 2;
      min-width: 0;
      overflow: hidden;
    }

    &[data-highlighted] {
      z-index: 0;
      color: var(--select-highlight-color, var(--color-background));

      &::before {
        content: '';
        position: absolute;
        z-index: -1;
        inset-block: 0;
        inset-inline: var(
          --select-highlight-inset-x,
          var(--popup-highlight-inset-x, var(--spacing-1))
        );
        border-radius: var(
          --select-highlight-radius,
          var(--popup-highlight-radius, var(--radius-sm))
        );
        background-color: var(--select-highlight-bg, var(--color-foreground));
      }
    }

    &[data-disabled] {
      opacity: var(--select-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }

    &[data-indicator-position='none'] {
      grid-template-columns: minmax(0, 1fr);
      padding-inline-start: var(
        --select-item-padding-x-start,
        var(--popup-item-padding-x-start, 1rem)
      );

      & > .itemIndicator {
        display: none;
      }

      & > .itemText {
        grid-column-start: 1;
      }
    }

    &[data-indicator-position='end'] {
      grid-template-columns:
        minmax(0, 1fr)
        var(--select-item-indicator-size, var(--popup-check-indicator-size, 0.75rem));

      & > .itemIndicator {
        grid-column-start: 2;
        justify-self: end;
      }

      & > .itemText {
        grid-column-start: 1;
      }
    }
  }

  .itemIndicatorIcon {
    width: var(--select-item-indicator-icon-size, 0.75rem);
    height: var(--select-item-indicator-icon-size, 0.75rem);
  }

  .itemTextContent {
    display: inline-flex;
    align-items: center;
    gap: var(--select-item-text-content-gap, var(--spacing-2));
    max-width: 100%;
    min-width: 0;
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: var(--select-item-text-icon-size, 1rem);
    height: var(--select-item-text-icon-size, 1rem);
    color: var(--select-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .separator {
    height: var(--select-separator-thickness, var(--border-width-sm));
    margin: var(--select-separator-margin-y, var(--popup-separator-margin-y, 0.375rem))
      var(--select-separator-margin-x, var(--popup-separator-margin-x-start, 1rem));
    background-color: var(
      --select-separator-color,
      var(--select-border-color, var(--color-border))
    );
  }

  .group {
    padding-bottom: var(--select-group-padding-bottom, var(--spacing-1));
  }

  .groupLabel {
    position: sticky;
    top: 0;
    z-index: 1;
    display: block;
    margin: 0;
    padding: var(--select-group-label-padding-top, var(--popup-group-label-padding-y, 0.35rem))
      var(--select-group-label-padding-x, var(--popup-group-label-padding-x-start, 0.625rem))
      var(--select-group-label-padding-bottom, var(--popup-group-label-padding-y, 0.35rem));
    background-color: var(--select-group-label-bg, var(--select-popup-bg, var(--color-popover)));
    color: var(--select-group-label-color, var(--color-muted-foreground));
    font-size: var(
      --select-group-label-font-size,
      var(--popup-group-label-font-size, var(--text-xs))
    );
    font-weight: var(--select-group-label-font-weight, var(--weight-semibold));
    line-height: var(
      --select-group-label-line-height,
      var(--popup-group-label-line-height, var(--line-height-text-xs))
    );
  }
}
